css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0f0f0f; color: white; height: 100vh; overflow: hidden; }
.app { display: flex; height: 100vh; }
.sidebar { width: 280px; background: #1a1a1a; border-right: 1px solid rgba(255,255,255,0.08); display: flex; flex-direction: column; flex-shrink: 0; }
.sidebar-header { display: flex; align-items: center; justify-content: space-between; padding: 20px 16px 12px; }
h1 { font-size: 20px; font-weight: 800; }
.new-btn { width: 32px; height: 32px; border-radius: 50%; border: none; background: #eab308; color: #0a0800; font-size: 20px; font-weight: 700; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.search-wrap { padding: 0 12px 12px; }
.search { width: 100%; height: 36px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.06); color: white; padding: 0 12px; font-size: 13px; outline: none; }
.note-list { flex: 1; overflow-y: auto; padding: 4px 8px; }
.note-item { padding: 14px 12px; border-radius: 12px; cursor: pointer; margin-bottom: 4px; border-left: 3px solid transparent; transition: all 0.15s; }
.note-item:hover { background: rgba(255,255,255,0.05); }
.note-item.active { background: rgba(234,179,8,0.1); border-left-color: #eab308; }
.note-item .ni-title { font-size: 14px; font-weight: 600; margin-bottom: 4px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.note-item .ni-preview { font-size: 12px; color: #6b7280; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.note-item .ni-date { font-size: 11px; color: #4b5563; margin-top: 4px; }
.editor { flex: 1; display: flex; flex-direction: column; }
.editor-toolbar { display: flex; align-items: center; justify-content: space-between; padding: 16px 24px; border-bottom: 1px solid rgba(255,255,255,0.07); gap: 16px; }
.title-input { flex: 1; background: transparent; border: none; color: white; font-size: 20px; font-weight: 700; outline: none; }
.toolbar-actions { display: flex; gap: 10px; align-items: center; }
#color-pick { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 8px 12px; border-radius: 10px; font-size: 13px; cursor: pointer; outline: none; }
.del-btn { padding: 8px 14px; border-radius: 10px; border: 1px solid rgba(239,68,68,0.3); background: rgba(239,68,68,0.08); color: #f87171; font-size: 13px; cursor: pointer; }
.content-area { flex: 1; background: transparent; border: none; color: #e2e8f0; font-size: 15px; line-height: 1.8; padding: 24px; resize: none; outline: none; font-family: inherit; }
.editor-footer { padding: 10px 24px; border-top: 1px solid rgba(255,255,255,0.07); font-size: 12px; color: #4b5563; }
.note-item.yellow { border-left-color: #eab308; } .note-item.blue { border-left-color: #3b82f6; } .note-item.green { border-left-color: #22c55e; } .note-item.pink { border-left-color: #ec4899; } .note-item.purple { border-left-color: #8b5cf6; }

js:
let notes = [
  { id: 1, title: 'Proje Fikirleri', content: 'Yeni uygulama için fikirler:\n- Pomodoro timer\n- Expense tracker\n- Habit tracker', color: 'yellow', date: '15 Oca' },
  { id: 2, title: 'Alışveriş Listesi', content: 'Süt\nEkmek\nDomates\nZeytinyağı\nMakarna', color: 'green', date: '14 Oca' },
  { id: 3, title: 'Toplantı Notları', content: 'Q1 hedefleri:\n- %20 büyüme\n- Yeni özellikler\n- Kullanıcı geri bildirimleri', color: 'blue', date: '13 Oca' }
];
let activeId = 1;
function render(filter='') {
  const list = document.getElementById('note-list');
  const filtered = notes.filter(n => n.title.toLowerCase().includes(filter) || n.content.toLowerCase().includes(filter));
  list.innerHTML = filtered.length === 0 ? '<div style="color:#4b5563;font-size:13px;padding:20px;text-align:center">Not bulunamadı</div>' :
    filtered.map(n => `
      <div class="note-item ${n.color} ${n.id===activeId?'active':''}" onclick="selectNote(${n.id})">
        <div class="ni-title">${n.title || 'Başlıksız'}</div>
        <div class="ni-preview">${n.content.split('\n')[0] || 'İçerik yok'}</div>
        <div class="ni-date">${n.date}</div>
      </div>
    `).join('');
  const active = notes.find(n => n.id === activeId);
  if (active) {
    document.getElementById('title-input').value = active.title;
    document.getElementById('content-area').value = active.content;
    document.getElementById('color-pick').value = active.color;
    document.getElementById('editor-footer').textContent = active.content.length + ' karakter · ' + active.date;
  }
}
function selectNote(id) { activeId = id; render(); }
function newNote() {
  const note = { id: Date.now(), title: '', content: '', color: 'yellow', date: 'Bugün' };
  notes.unshift(note); activeId = note.id; render();
  document.getElementById('title-input').focus();
}
function saveNote() {
  const n = notes.find(n => n.id === activeId);
  if (!n) return;
  n.title = document.getElementById('title-input').value;
  n.content = document.getElementById('content-area').value;
  n.date = 'Şimdi';
  render();
}
function changeColor(c) { const n = notes.find(n => n.id === activeId); if (n) { n.color = c; render(); } }
function deleteNote() {
  if (!confirm('Bu notu silmek istediğinizden emin misiniz?')) return;
  notes = notes.filter(n => n.id !== activeId);
  activeId = notes[0]?.id || null;
  render();
}
function searchNotes(q) { render(q.toLowerCase()); }
render();
